  ('pukao-7fec267e-moex-00012', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '韋伯（M.Weber）所定義的合法理性型權威，可能產生何種隱憂？', '["難以抑制或侷限在位者的職權", "社會大眾盲目崇拜與服從掌權者", "父權主義", "官僚組織的蔓延擴大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00013', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '憲政主義（constitutionalism）是當代民主政治運作的基礎，有限政府（limitedgovernment）是其中 的一項重要內涵。下列何項敘述最符合有限政府的概念？', '["政府規模不應該過大，避免過多冗員，也可提升政府效能", "政府應避免浪費預算，以及使民眾過於依賴政府", "藉由制度上的設計來達到限制政府權力，保障人民權利之目的", "民選政治人物任期予以限制，避免權力集中少數人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00014', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '關於政治文化研究的重要著作之敘述，下列何者正確？', '["白魯洵（L.Pye）研究那些因素影響義大利地方政府的施政表現，發現政治制度是最重要的因素", "阿蒙（G.Almond）與佛巴（S.Verba）在其著作「基督教倫理與資本主義精神」一書強調經濟 發展對價值觀念的影響", "韋伯（M.Weber）以調查研究法針對美國、英國、西德、義大利、墨西哥五個國家的公民文化， 發現西德民眾最積極參與社區事務", "英格哈特（R. Inglehart）的研究發現，當一個社會的經濟狀況良好，物質生活無虞後，人們的 價值觀可能改變，轉而強調尊嚴與自我實踐的重要性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00015', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '道爾（R.Dahl）曾定義一個多元政體需具備7項條件，下列何者不在其列？', '["新聞自由", "普遍選舉權", "自由市場", "言論自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00016', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '有關剛性憲法與柔性憲法的分類，下列敘述何者錯誤？', '["此種分類是由英國學者戴雪（A.V.Dicey）所提出", "剛性憲法指的是憲法必須經由特殊程序才能修改，不同於一般法律的修改程序", "從各國憲法變遷的實務經驗來看，剛性與柔性的分類並不完全準確", "憲法修改若須經由公民投票通過，即屬於柔性憲法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00017', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '憲政主義中關於有限政府的核心精神與描述 ，下列何者錯誤？', '["強調行政立法的權力融合", "三權分立是常見的類型", "目的是為了防止國家機器濫權", "可分為中央與地方的分權與自治"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00018', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '有關議會內閣制的敘述，下列何者錯誤？', '["行政立法兩權的關係為權力融合", "具有二元民意，強調分立制衡", "通常具有倒閣與解散國會的設計", "行政首長任期不固定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00019', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d68e6020', 'sub-pukao-7fec267e-01', NULL, 'single_choice', '有關我國立法院之敘述，下列何者錯誤？', '["有立法權而無立法調查權", "屬於單一國會制", "有預算議決與審計權", "可對行政院院長提出不信任案"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "25f5ab985b41", "answer_pdf_sha1": "a6849f6e6747", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政治學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
